    /// Todo: 支持areas的lazy allocation
    /// 文件私有/共享映射
    /// key是vpn_range起始虚拟地址
    pub areas: BTreeMap<VirtPageNum, MapArea>,
    /// System V shared memory
    /// shm_start_address -> shmid
    pub addr2shmid: BTreeMap<usize, usize>,
}

