    }
    tp
}
#[cfg(target_arch = "loongarch64")]
#[allow(unused)]
pub fn current_tp() -> usize {
    let mut tp: usize;
    unsafe {
        asm!("addi.d {}, $r2, 0", out(reg) tp);
    }
    tp
}

